#include <iostream>\n#include <cmath>\n#include <iomanip>\n\nstruct Point {\n  explicit Point(double x, double y) : x(x), y(y) {\n  }\n  double x;\n  double y;\n};\n\nclass Vector {\n public:\n  explicit Vector(const Point& start, const Point& end) : x_(end.x - start.x), y_(end.y - start.y) {\n  }\n\n  explicit Vector(double x, double y) : x_(x), y_(y) {\n  }\n\n  double GetDist() {\n    return sqrt(x_ * x_ + y_ * y_);\n  }\n\n  double operator*(const Vector& vector) {\n    return x_ * vector.x_ + y_ * vector.y_;\n  }\n\n  double operator^(const Vector& vector) {\n    return x_ * vector.y_ - y_ * vector.x_;\n  }\n\n  Vector operator+(const Vector& vector) {\n    return Vector(x_ + vector.x_, y_ + vector.y_);\n  }\n\n  friend std::ostream& operator<<(std::ostream& stream, const Vector& vector) {\n    stream << vector.x_ << ' ' << vector.y_;\n    return stream;\n  }\n\n private:\n  double x_;\n  double y_;\n};\n\nint main() {\n  std::cout << std::setprecision(7);\n  double x1, y1, x2, y2;\n  std::cin >> x1 >> y1 >> x2 >> y2;\n  Vector a(Point(x1, y1), Point(x2, y2));\n\n  std::cin >> x1 >> y1 >> x2 >> y2;\n  Vector b(Point(x1, y1), Point(x2, y2));\n\n  std::cout << a.GetDist() << ' ' << b.GetDist() << '\\n';\n  std::cout << a + b << '\\n';\n  std::cout << a * b << ' ' << (a ^ b) << '\\n';\n  std::cout << std::abs(a ^ b) / 2 << std::endl;\n  return 0;\n}